sql:
SELECT sailboats.sailboat_id, sailboats.sail_number
FROM sailboats
INNER JOIN results ON sailboats.sailboat_id = results.sailboat_id;

SELECT class_id, class_name, description
FROM classes
WHERE class_id = 1;

SELECT *
FROM sailboats
WHERE class_id = 1;

SELECT handicap_value
FROM handicaps
WHERE sailboat_id = 1;

SELECT sailboat_id, owner_name
FROM sailboats
WHERE owner_name = 'John Doe';

SELECT helm_name, total_competitions_participated
FROM crews
WHERE total_competitions_participated = (
    SELECT MAX(total_competitions_participated) FROM crews
);

SELECT name 
FROM competitions 
WHERE date = '2022-05-01';

SELECT AVG(position) AS Average_Position, AVG(elapsed_time) AS Average_Elapsed_Time
FROM results
WHERE competition_id = 1 AND crew_id = 0;

SELECT location, COUNT(*) AS total_competitions
FROM competitions
GROUP BY location;

SELECT sail_number, sailboat_id
FROM sailboats
WHERE sailboat_id NOT IN (SELECT sailboat_id FROM results);

SELECT class_id, COUNT(*) AS sailboat_count
FROM sailboats
GROUP BY class_id;

SELECT MAX(handicap_value)
FROM handicaps
WHERE sailboat_id = 1;

SELECT sailboats.sailboat_id, classes.class_name
FROM sailboats
JOIN classes ON sailboats.class_id = classes.class_id;

SELECT sailboat_id, sail_number
FROM sailboats
ORDER BY build_year DESC;

